  var prevX = prevBlock.x
  return uniform(prevX - prevW, prevX + prevW)
}

var ypos = function (prevBlock, h) {
  var prevY = prevBlock.y
  var prevH = prevBlock.dims[1]
  return prevY - (prevH + h)
}

