var utterances = ["blue","green","square","circle"]

// meaning function to interpret the utterances
var meaning = function(utterance, obj){
  (utterance === "blue" || utterance === "green") ? utterance === obj.color :
  (utterance === "circle" || utterance === "square") ? utterance === obj.shape :
  true
}

var alpha = 1

// literal listener
var literalListener = function(utterance){
  Infer({model: function(){
    var obj = meaningPrior();
    condition(meaning(utterance, obj))
    return obj
  }})
}

// pragmatic speaker
var speaker = function(obj){
  Infer({model: function(){
    var utterance = uniformDraw(utterances)
    factor(alpha * literalListener(utterance).score(obj))
    return utterance
  }})
}

// pragmatic listener
var pragmaticListener = function(utterance){
  Infer({model: function(){
    var obj = meaningPrior()
    observe(speaker(obj),utterance)
    return obj
  }})
}

// pragmatic speaker2
var speaker2 = function(obj){
  Infer({model: function(){
    var utterance = uniformDraw(utterances)
    factor(alpha * pragmaticListener(utterance).score(obj))
    return utterance
  }})
}

// pragmatic listener #2
var listener3 = function(utterance){
  Infer({model: function(){
    var obj = meaningPrior()
    observe(speaker2(obj),utterance)
    return obj
  }})
}

print("L1's interpretation of 'blue'")
viz.table(pragmaticListener("blue"))

print("L2's interpretation of 'blue'")
viz.table(listener3("blue"))

//Helper function to compare arrays
var comparray = function(arr1,arr2){
  return (JSON.stringify(arr1) === JSON.stringify(arr2))
} 

var mm = Infer({method:'MCMC', burn:10000, samples: 50000, onlyMAP:false}, function() {

  let vocab = ['dogs', 'cats', 'chase', 'sleep', 'stop'];

  var wordToDistribution = mem(function(word) {
    return dirichletDrift({alpha:ones([vocab.length,1]), concentration:10})
  })

  var transition = function(word) {
    return categorical({ps: wordToDistribution(word), vs: vocab})
  }


  let obs = ['dogs', 'chase', 'cats'];

  let generateSentence = function(lastState, sentence) {
    let word = transition(lastState);
    if (word == 'stop') return [];
    return [word].concat(generateSentence(word, sentence));
  }

  condition(comparray(obs, generateSentence('start')))

  return transition('chase');

})

