var transition = function(state, action) {
  var nextstate = state + action
  return (nextstate < 0) ? 4 :
         (nextstate > 4) ? 0 :
         nextstate;
};

var act = function(state, timeLeft) {
    return Infer({ model() {
      var action = uniformDraw([-2, -1, 0, 1, 2]);
      var eu = expectedUtility(state, action, timeLeft);
      factor(100 * eu);
      return action;
    }});
  };

