var vendingMachine = function(state, action) {
  return action == 'a' ? categorical({vs: ['bagel', 'cookie', 'doughnut'],
                                      ps: [.8, .1, .1]}) :
         action == 'b' ? categorical({vs: ['bagel', 'cookie', 'doughnut'],
