var L = function(x,y,w,z){
  var a = flip(0.2)
  var b = flip(0.2)
  var c = flip(0.2)
  var d = a || x || b || c
  var e = (d ? 1 : 0) + y
  var g = e + w + z + flip()
  return g
}

